<script setup lang="ts">withDefaults(defineProps<{title:string;image:string;tag?:string;views?:number;comments?:number;tone?:'life'|'study';state?:'default'|'selected'|'ended'}>(),{tone:'life',state:'default'})</script><template><article class="xj-card xj-content-card" :class="tone" :style="state==='selected'?{borderColor:tone==='life'?'#5BD98E':'#73A5FA'}:{}"><div style="position:relative"><img :src="image" class="xj-thumb"/><span v-if="tag" class="xj-badge success" style="position:absolute;left:10px;top:10px">{{tag}}</span><span v-if="state==='ended'" class="xj-badge neutral" style="position:absolute;right:10px;top:10px">已结束</span></div><div class="xj-card-body"><h3 class="xj-card-title">{{title}}</h3><div class="xj-card-meta"><span>◉ {{views||0}}</span><span>▣ {{comments||0}}</span><slot name="meta"/></div></div></article></template>
